import { useState, useEffect } from 'react';
import './App.css';

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL;

function App() {
  const [products, setProducts] = useState([]);
  const [bestSellers, setBestSellers] = useState([]);
  const [cart, setCart] = useState([]);
  const [authToken, setAuthToken] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showCart, setShowCart] = useState(false);

  const [newProduct, setNewProduct] = useState({
    name: '',
    price: '',
    file: null
  });

  const [uploading, setUploading] = useState(false);

  // ================= JWT Decode =================
  const decodeJWT = (token) => {
    try {
      const base64Url = token.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(
        window.atob(base64)
          .split('')
          .map(c => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
          .join('')
      );
      return JSON.parse(jsonPayload);
    } catch {
      return null;
    }
  };

  // ================= Session =================
  const checkActiveSession = () => {
    const savedToken = localStorage.getItem('cognito_jwt_token');

    if (savedToken) {
      setAuthToken(savedToken);

      const decoded = decodeJWT(savedToken);
      if (decoded) {
        const groups = decoded["cognito:groups"] || [];
        setIsAdmin(groups.includes("Admins"));
      }
    }
  };

  // ================= Login Simulation =================
  const handleLoginSimulation = (role) => {
    const payload =
      role === 'admin'
        ? { "cognito:groups": ["Admins"], username: "admin_user" }
        : { username: "regular_user" };

    const token = `header.${window.btoa(JSON.stringify(payload))}.sig`;

    localStorage.setItem('cognito_jwt_token', token);
    setAuthToken(token);
    checkActiveSession();
  };

  const handleLogout = () => {
    localStorage.removeItem('cognito_jwt_token');
    setAuthToken(null);
    setIsAdmin(false);
  };

  // ================= Products =================
  const fetchProducts = async () => {
  try {
    const res = await fetch(`${API_BASE_URL}/products`);
    const data = await res.json();

    console.log("🔥 PRODUCTS RESPONSE:", data); // 👈 هنا تحطه

    setProducts(data.data || []);
  } catch (err) {
    console.log("ERROR:", err);
  }
};

  // ================= Best Sellers =================
  useEffect(() => {
    fetch(`${API_BASE_URL}/best-sellers`)
      .then(res => res.json())
      .then(data => setBestSellers(data.data))
      .catch(() => console.log("Best sellers not loaded"));
  }, []);

  // ================= Init =================
  useEffect(() => {
    fetchProducts();
    checkActiveSession();

    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ================= Upload + Add Product =================
  const handleAddProduct = async (e) => {
    e.preventDefault();
    setUploading(true);

    try {
      const urlResponse = await fetch(
        `${API_BASE_URL}/admin/products/upload-url`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${authToken}`,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify({
            file_name: newProduct.file.name
          })
        }
      );

      const { upload_url, file_url } = await urlResponse.json();

      await fetch(upload_url, {
        method: 'PUT',
        body: newProduct.file
      });

      await fetch(`${API_BASE_URL}/admin/products`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${authToken}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: newProduct.name,
          price: newProduct.price,
          image_url: file_url
        })
      });

      alert("Product added successfully!");
      fetchProducts();

    } catch {
      alert("Operation failed.");
    } finally {
      setUploading(false);
    }
  };

  // ================= Checkout =================
  const handleCheckout = async () => {
    try {
      const res = await fetch(`${API_BASE_URL}/checkout`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${authToken}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          items: cart,
          total: cart.reduce((s, i) => s + i.price, 0)
        })
      });

      if (res.ok) {
        alert("Order placed!");
        setCart([]);
        setShowCart(false);
      }
    } catch {
      alert("Checkout failed.");
    }
  };

  // ================= UI =================
  return (
    <div style={{ fontFamily: 'Arial', padding: 20, background: '#f8fafc', minHeight: '100vh' }}>

      <header style={{ display: 'flex', justifyContent: 'space-between', background: '#0f172a', color: 'white', padding: 15 }}>
        <h2>Cloud Store ☁️</h2>

        <div>
          {!authToken ? (
            <>
              <button onClick={() => handleLoginSimulation('user')}>User</button>
              <button onClick={() => handleLoginSimulation('admin')} style={{ marginLeft: 10 }}>Admin</button>
            </>
          ) : (
            <button onClick={handleLogout}>Logout</button>
          )}

          <button onClick={() => setShowCart(!showCart)} style={{ marginLeft: 15 }}>
            Cart ({cart.length})
          </button>
        </div>
      </header>

      {/* CART */}
      {showCart && (
        <div style={{ background: 'white', padding: 20, marginTop: 20 }}>
          <h3>Cart</h3>

          {cart.map((i, idx) => (
            <p key={idx}>{i.name} - ${i.price}</p>
          ))}

          <button onClick={handleCheckout}>
            Checkout
          </button>
        </div>
      )}

      {/* ADMIN */}
      {isAdmin && (
        <div style={{ marginTop: 30, padding: 20, background: '#fff7ed' }}>
          <h3>Admin Panel</h3>

          <form onSubmit={handleAddProduct}>
            <input
              placeholder="Name"
              onChange={e => setNewProduct({ ...newProduct, name: e.target.value })}
              required
            />

            <input
              type="number"
              placeholder="Price"
              onChange={e => setNewProduct({ ...newProduct, price: e.target.value })}
              required
            />

            <input
              type="file"
              onChange={e => setNewProduct({ ...newProduct, file: e.target.files[0] })}
              required
            />

            <button type="submit" disabled={uploading}>
              Add Product
            </button>
          </form>
        </div>
      )}

      {/* PRODUCTS */}
      <h3>Products</h3>

      <div style={{ display: 'flex', gap: 20, flexWrap: 'wrap' }}>
        {products.map(p => (
          <div key={p.id} style={{ border: '1px solid #ddd', padding: 15 }}>
            <img src={p.image_url} width="120" />
            <h4>{p.name}</h4>
            <p>${p.price}</p>
            <button onClick={() => setCart([...cart, p])}>Add</button>
          </div>
        ))}
      </div>

      {/* BEST SELLERS */}
      <h3>Best Sellers</h3>

      <div style={{ display: 'flex', gap: 10 }}>
        {bestSellers.map(p => (
          <div key={p.id} style={{ border: '1px solid orange', padding: 10 }}>
            {p.name}
          </div>
        ))}
      </div>

    </div>
  );
}

export default App;
